import java.util.*;

class Solution {
    // Function to find the length of the longest substring with at most K distinct characters
    public int lengthOfLongestSubstringKDistinct(String s, int k) {
        // Store the maximum length of valid substring
        int maxLength = 0;

        // Try every possible starting index
        for (int i = 0; i < s.length(); i++) {
            // Use map to store character frequencies
            Map<Character, Integer> freq = new HashMap<>();

            // Try all possible substrings starting at i
            for (int j = i; j < s.length(); j++) {
                // Add or update frequency
                freq.put(s.charAt(j), freq.getOrDefault(s.charAt(j), 0) + 1);

                // If distinct chars exceed k, stop expanding
                if (freq.size() > k) break;

                // Update maxLength
                maxLength = Math.max(maxLength, j - i + 1);
            }
        }

        // Return final answer
        return maxLength;
    }
}

public class Main {
    public static void main(String[] args) {
        Solution sol = new Solution();
        String s = "eceba";
        int k = 2;

        System.out.println(sol.lengthOfLongestSubstringKDistinct(s, k));
    }
}

